from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import os
import time
import secrets

app = Flask(__name__)

w3 = Web3()

NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
NONCE_STORE = {}

def cleanup_nonces():
    now = int(time.time())
    expired = [k for k, v in NONCE_STORE.items() if now - v["created_at"] > NONCE_TTL_SECONDS]
    for k in expired:
        NONCE_STORE.pop(k, None)

def generate_nonce():
    return secrets.token_urlsafe(16)

@app.route("/auth/nonce", methods=["POST"])
def auth_nonce():
    data = request.get_json(silent=True) or {}
    address = data.get("address")
    if not address or not Web3.is_address(address):
        return jsonify({"error": "Invalid or missing address"}), 400

    cleanup_nonces()
    nonce = generate_nonce()
    NONCE_STORE[address.lower()] = {
        "nonce": nonce,
        "created_at": int(time.time()),
    }

    message = f"Sign this message to authenticate.\n\nAddress: {address}\nNonce: {nonce}"
    return jsonify({"address": address, "nonce": nonce, "message": message})

@app.route("/auth/verify", methods=["POST"])
def auth_verify():
    data = request.get_json(silent=True) or {}
    address = data.get("address")
    message = data.get("message")
    signature = data.get("signature")

    if not address or not Web3.is_address(address):
        return jsonify({"error": "Invalid or missing address"}), 400
    if not message or not signature:
        return jsonify({"error": "Missing message or signature"}), 400

    cleanup_nonces()
    stored = NONCE_STORE.get(address.lower())
    if not stored:
        return jsonify({"error": "Nonce not found for address"}), 400

    expected_nonce = stored["nonce"]
    if expected_nonce not in message:
        return jsonify({"error": "Invalid message nonce"}), 400

    try:
        eth_message = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(eth_message, signature=signature)
    except Exception:
        return jsonify({"error": "Signature verification failed"}), 400

    if recovered_address.lower() != address.lower():
        return jsonify({"error": "Recovered address does not match"}), 401

    NONCE_STORE.pop(address.lower(), None)

    token = secrets.token_urlsafe(32)
    return jsonify({
        "authenticated": True,
        "address": recovered_address,
        "token": token
    })

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})

if __name__ == "__main__":
    host = os.getenv("HOST", "0.0.0.0")
    port = int(os.getenv("PORT", "8000"))
    app.run(host=host, port=port)